        //                 "noAllowMarketEndTime": "1710486000000",
        //                 "limitOrderStartTime": "0",
        //                 "limitOrderEndTime": "0",
        //                 "limitMinPrice": "0",
        //                 "limitMaxPrice": "0",
        //                 "filterType": "OPEN_QUOTE"
        //             }
        //         ]
        //     }
        //
        // swap
        //     {
        //         "filters": [
        //             {
        //                 "minPrice": "0.1",
        //                 "maxPrice": "100000.00000000",
        //                 "tickSize": "0.1",
        //                 "filterType": "PRICE_FILTER"
        //             },
        //             {
        //                 "minQty": "0.001",
        //                 "maxQty": "10",
        //                 "stepSize": "0.001",
        //                 "marketOrderMinQty": "0",
        //                 "marketOrderMaxQty": "0",
        //                 "filterType": "LOT_SIZE"
        //             },
        //             {
        //                 "minNotional": "0",
        //                 "filterType": "MIN_NOTIONAL"
        //             },
        //             {
        //                 "maxSellPrice": "999999",
        //                 "buyPriceUpRate": "0.05",
        //                 "sellPriceDownRate": "0.05",
        //                 "maxEntrustNum": 200,
        //                 "maxConditionNum": 200,
        //                 "filterType": "LIMIT_TRADING"
        //             },
        //             {
        //                 "buyPriceUpRate": "0.05",
        //                 "sellPriceDownRate": "0.05",
        //                 "filterType": "MARKET_TRADING"
        //             },
        //             {
        //                 "noAllowMarketStartTime": "0",
        //                 "noAllowMarketEndTime": "0",
        //                 "limitOrderStartTime": "0",
        //                 "limitOrderEndTime": "0",
        //                 "limitMinPrice": "0",
        //                 "limitMaxPrice": "0",
        //                 "filterType": "OPEN_QUOTE"
        //             }
        //         ],
        //         "exchangeId": "301",
        //         "symbol": "BTCUSDT-PERPETUAL",
        //         "symbolName": "BTCUSDT-PERPETUAL",
        //         "status": "TRADING",
        //         "baseAsset": "BTCUSDT-PERPETUAL",
        //         "baseAssetPrecision": "0.001",
        //         "quoteAsset": "USDT",
        //         "quoteAssetPrecision": "0.1",
        //         "icebergAllowed": false,
        //         "inverse": false,
        //         "index": "USDT",
        //         "marginToken": "USDT",
        //         "marginPrecision": "0.0001",
        //         "contractMultiplier": "0.001",
        //         "underlying": "BTC",
        //         "riskLimits": [
        //             {
        //                 "riskLimitId": "200000722",
        //                 "quantity": "1000.00",
        //                 "initialMargin": "0.10",
        //                 "maintMargin": "0.005",
        //                 "isWhite": false
        //             },
        //             {
        //                 "riskLimitId": "200000723",
        //                 "quantity": "2000.00",
        //                 "initialMargin": "0.10",
        //                 "maintMargin": "0.01",
        //                 "isWhite": false
        //             }
        //         ]
        //     }
        //
        Object marketId = this.safeString(market, "symbol");
        Object quoteId = this.safeString(market, "quoteAsset");
        Object quote = this.safeCurrencyCode(quoteId);
        Object settleId = this.safeString(market, "marginToken");
        Object settle = this.safeCurrencyCode(settleId);
        Object baseId = this.safeString(market, "baseAsset");
        Object marketType = ((Object)"spot");
        Object isSpot = true;
        Object isSwap = false;
        Object suffix = "";
        Object parts = Helpers.split(marketId, "-");
        Object secondPart = this.safeString(parts, 1);
        if (Helpers.isTrue(Helpers.isEqual(secondPart, "PERPETUAL")))
        {
            marketType = "swap";
            isSpot = false;
            isSwap = true;
            baseId = this.safeString(market, "underlying");
            suffix = Helpers.add(suffix, Helpers.add(":", settleId));
        }
        Object base = this.safeCurrencyCode(baseId);
        Object symbol = Helpers.add(Helpers.add(Helpers.add(base, "/"), quote), suffix);
        Object status = this.safeString(market, "status");
        Object active = Helpers.isEqual(status, "TRADING");
        Object isLinear = null;
        Object subType = null;
        Object isInverse = this.safeBool(market, "inverse");
        if (Helpers.isTrue(!Helpers.isEqual(isInverse, null)))
        {
            if (Helpers.isTrue(isInverse))
            {
                isLinear = false;
                subType = "inverse";
            } else
            {
                isLinear = true;
                subType = "linear";
            }
        }
        Object filtersList = this.safeList(market, "filters", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object filters = this.indexBy(filtersList, "filterType");
        Object priceFilter = this.safeDict(filters, "PRICE_FILTER", new java.util.HashMap<String, Object>() {{}});
        Object amountFilter = this.safeDict(filters, "LOT_SIZE", new java.util.HashMap<String, Object>() {{}});
        Object costFilter = this.safeDict(filters, "MIN_NOTIONAL", new java.util.HashMap<String, Object>() {{}});
        Object minCostString = this.omitZero(this.safeString(costFilter, "min_notional"));
        Object contractSizeString = this.safeString(market, "contractMultiplier");
        Object amountPrecisionString = this.safeString(amountFilter, "stepSize");
        Object amountMinLimitString = this.safeString(amountFilter, "minQty");
        Object amountMaxLimitString = this.safeString(amountFilter, "maxQty");
        Object minLeverage = null;
        Object maxLeverage = null;
        if (Helpers.isTrue(isSwap))
        {
            amountPrecisionString = Precise.stringDiv(amountPrecisionString, contractSizeString);
            amountMinLimitString = Precise.stringDiv(amountMinLimitString, contractSizeString);
            amountMaxLimitString = Precise.stringDiv(amountMaxLimitString, contractSizeString);
            Object riskLimits = this.safeList(market, "riskLimits");
            if (Helpers.isTrue(!Helpers.isEqual(riskLimits, null)))
            {
                Object first = this.safeDict(riskLimits, 0);
                Object arrayLength = Helpers.getArrayLength(riskLimits);
                Object last = this.safeDict(riskLimits, Helpers.subtract(arrayLength, 1));
                Object minInitialMargin = this.safeString(first, "initialMargin");
                Object maxInitialMargin = this.safeString(last, "initialMargin");
                if (Helpers.isTrue(Precise.stringGt(minInitialMargin, maxInitialMargin)))
                {
                    var minInitialMarginmaxInitialMarginVariable = new java.util.ArrayList<Object>(java.util.Arrays.asList(maxInitialMargin, minInitialMargin));
                    minInitialMargin = ((java.util.List<Object>) minInitialMarginmaxInitialMarginVariable).get(0);
                    maxInitialMargin = ((java.util.List<Object>) minInitialMarginmaxInitialMarginVariable).get(1);
                }
                minLeverage = this.parseToInt(Precise.stringDiv("1", maxInitialMargin));
                maxLeverage = this.parseToInt(Precise.stringDiv("1", minInitialMargin));
            }
        }
        Object tradingFees = this.safeDict(this.fees, "trading");
        Object fees = ((Helpers.isTrue(isSpot))) ? this.safeDict(tradingFees, "spot") : this.safeDict(tradingFees, "swap");
        final Object finalBase = base;
        final Object finalBaseId = baseId;
        final Object finalMarketType = marketType;
        final Object finalSubType = subType;
        final Object finalIsSpot = isSpot;
