    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        //     {
        //         "t": 1721685896846,
        //         "s": "BTCUSDT-PERPETUAL",
        //         "c": "67756.7",
        //         "h": "68479.9",
        //         "l": "66594.3",
        //         "o": "68279.7",
        //         "b": "67756.6",
        //         "a": "67756.7",
        //         "v": "1604722",
        //         "qv": "108827258.7761"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(ticker, "t");
        Object marketId = this.safeString(ticker, "s");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object last = this.safeString(ticker, "c");
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", HashkeyCore.this.iso8601(timestamp) );
            put( "high", HashkeyCore.this.safeString(ticker, "h") );
            put( "low", HashkeyCore.this.safeString(ticker, "l") );
            put( "bid", HashkeyCore.this.safeString(ticker, "b") );
            put( "bidVolume", null );
            put( "ask", HashkeyCore.this.safeString(ticker, "a") );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", HashkeyCore.this.safeString(ticker, "o") );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", null );
            put( "average", null );
            put( "baseVolume", HashkeyCore.this.safeString(ticker, "v") );
            put( "quoteVolume", HashkeyCore.this.safeString(ticker, "qv") );
            put( "info", ticker );
        }}, market);
    }

