    /**
     * @method
     * @name hashkey#fetchBalance
     * @description query for balance and get the amount of funds available for trading or funds locked in orders
     * @see https://hashkeyglobal-apidoc.readme.io/reference/get-account-information
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.accountId] account ID, for Master Key only
     * @param {string} [params.type] 'spot' or 'swap' - the type of the market to fetch balance for (default 'spot')
     * @returns {object} a [balance structure]{@link https://docs.ccxt.com/?id=balance-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchBalance(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object request = new java.util.HashMap<String, Object>() {{}};
            Object methodName = "fetchBalance";
            Object marketType = "spot";
            var marketTypeparametersVariable = this.handleMarketTypeAndParams(methodName, null, parameters, marketType);
            marketType = ((java.util.List<Object>) marketTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marketTypeparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(marketType, "swap")))
            {
                Object response = (this.privateGetApiV1FuturesBalance(parameters)).join();
                //
                //     [
                //         {
                //             "balance": "30.63364672",
                //             "availableBalance": "28.85635534",
                //             "positionMargin": "4.3421",
                //             "orderMargin": "0",
                //             "asset": "USDT",
                //             "crossUnRealizedPnl": "2.5649"
                //         }
                //     ]
                //
                Object balance = this.safeDict(response, 0, new java.util.HashMap<String, Object>() {{}});
                return this.parseSwapBalance(balance);
            } else if (Helpers.isTrue(Helpers.isEqual(marketType, "spot")))
            {
                Object response = (this.privateGetApiV1Account(this.extend(request, parameters))).join();
                //
                //     {
                //         "balances": [
                //             {
                //                 "asset":"USDT",
                //                 "assetId":"USDT",
                //                 "assetName":"USDT",
                //                 "total":"40",
                //                 "free":"40",
                //                 "locked":"0"
                //             },
                //             ...
                //         ],
                //         "userId": "1732885739572845312"
                //     }
                //
                return this.parseBalance(response);
            } else
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " "), methodName), "() is not supported for "), marketType), " type of markets")) ;
            }
        });

    }

    public Object parseBalance(Object balance)
    {
        //
        //     {
        //         "balances": [
        //             {
        //                 "asset":"USDT",
        //                 "assetId":"USDT",
        //                 "assetName":"USDT",
        //                 "total":"40",
        //                 "free":"40",
        //                 "locked":"0"
        //             },
        //             ...
        //         ],
        //         "userId": "1732885739572845312"
        //     }
        //
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", balance );
        }};
        Object balances = this.safeList(balance, "balances", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(balances)); i++)
        {
            Object balanceEntry = Helpers.GetValue(balances, i);
            Object currencyId = this.safeString(balanceEntry, "asset");
            Object code = this.safeCurrencyCode(currencyId);
            Object account = this.account();
            Helpers.addElementToObject(account, "total", this.safeString(balanceEntry, "total"));
            Helpers.addElementToObject(account, "free", this.safeString(balanceEntry, "free"));
            Helpers.addElementToObject(account, "used", this.safeString(balanceEntry, "locked"));
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

    public Object parseSwapBalance(Object balance)
    {
        //
        //     {
        //         "balance": "30.63364672",
        //         "availableBalance": "28.85635534",
        //         "positionMargin": "4.3421",
        //         "orderMargin": "0",
        //         "asset": "USDT",
        //         "crossUnRealizedPnl": "2.5649"
        //     }
        //
        Object currencyId = this.safeString(balance, "asset");
        Object code = this.safeCurrencyCode(currencyId);
        Object account = this.account();
        Helpers.addElementToObject(account, "total", this.safeString(balance, "balance"));
        Object positionMargin = this.safeString(balance, "positionMargin");
        Object orderMargin = this.safeString(balance, "orderMargin");
        Helpers.addElementToObject(account, "used", Precise.stringAdd(positionMargin, orderMargin));
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", balance );
        }};
        Helpers.addElementToObject(result, code, account);
        return this.safeBalance(result);
    }

