    public Object parseDepositAddress(Object depositAddress, Object... optionalArgs)
    {
        //
        //     {
        //         "canDeposit": true,
        //         "address": "0x61AAd7F763e2C7fF1CC996918740F67f9dC8BF4e",
        //         "addressExt": "",
        //         "minQuantity": "1",
        //         "needAddressTag": false,
        //         "requiredConfirmTimes": 64,
        //         "canWithdrawConfirmTimes": 64,
        //         "coinType": "ERC20_TOKEN"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object address = this.safeString(depositAddress, "address");
        this.checkAddress(address);
        Object tag = this.safeString(depositAddress, "addressExt");
        if (Helpers.isTrue(Helpers.isEqual(tag, "")))
        {
            tag = null;
        }
        final Object finalTag = tag;
        return new java.util.HashMap<String, Object>() {{
            put( "info", depositAddress );
            put( "currency", Helpers.GetValue(currency, "code") );
            put( "network", null );
            put( "address", address );
            put( "tag", finalTag );
        }};
    }

