    /**
     * @method
     * @name hashkey#createOrders
     * @description create a list of trade orders (all orders should be of the same symbol)
     * @see https://hashkeyglobal-apidoc.readme.io/reference/create-multiple-orders
     * @see https://hashkeyglobal-apidoc.readme.io/reference/batch-create-new-futures-order
     * @param {Array} orders list of orders to create, each object should contain the parameters required by createOrder, namely symbol, type, side, amount, price and params
     * @param {object} [params] extra parameters specific to the api endpoint
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrders(Object orders, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object ordersRequests = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(orders)); i++)
            {
                Object rawOrder = Helpers.GetValue(orders, i);
                Object symbol = this.safeString(rawOrder, "symbol");
                Object type = this.safeString(rawOrder, "type");
                Object side = this.safeString(rawOrder, "side");
                Object amount = this.safeNumber(rawOrder, "amount");
                Object price = this.safeNumber(rawOrder, "price");
                Object orderParams = this.safeDict(rawOrder, "params", new java.util.HashMap<String, Object>() {{}});
                Object orderRequest = this.createOrderRequest(symbol, type, side, amount, price, orderParams);
                Object clientOrderId = this.safeString(orderRequest, "clientOrderId");
                if (Helpers.isTrue(Helpers.isEqual(clientOrderId, null)))
                {
                    Helpers.addElementToObject(orderRequest, "clientOrderId", this.uuid()); // both spot and swap endpoints require clientOrderId
                }
                ((java.util.List<Object>)ordersRequests).add(orderRequest);
            }
            Object firstOrder = Helpers.GetValue(ordersRequests, 0);
            Object firstSymbol = this.safeString(firstOrder, "symbol");
            Object market = this.market(firstSymbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "orders", ordersRequests );
            }};
            Object response = null;
            if (Helpers.isTrue(Helpers.GetValue(market, "spot")))
            {
                response = (this.privatePostApiV1SpotBatchOrders(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.GetValue(market, "swap")))
            {
                response = (this.privatePostApiV1FuturesBatchOrders(this.extend(request, parameters))).join();
            } else
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " "), "createOrderRequest() is not supported for "), Helpers.GetValue(market, "type")), " type of markets")) ;
            }
            Object result = this.safeList(response, "result", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object responseOrders = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(result)); i++)
            {
                Object responseEntry = this.safeDict(result, i, new java.util.HashMap<String, Object>() {{}});
                Object responseOrder = this.safeDict(responseEntry, "order", new java.util.HashMap<String, Object>() {{}});
                ((java.util.List<Object>)responseOrders).add(responseOrder);
            }
            return this.parseOrders(responseOrders);
        });

    }

